// NOTIFICAR ERROR EN EL GRUPO
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363424829792074@g.us';

const inp  = $input.item.json;
const errorMsg = inp.message || inp.error || 'Error desconocido';
const ahora = new Date().toLocaleString('es-PE', { timeZone: 'America/Lima' });

const texto = `⚠️ *ERROR — Alertas Entregas Control Deudas*\n🗓️ ${ahora}\n${'─'.repeat(30)}\nNo se pudo consultar la API de entregas.\n\nError: ${errorMsg}\n\nRevisa los logs en Dokploy.`;

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
    headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
    body: { number: GROUP_JID, text: texto },
    json: true,
    timeout: 10000
  });
} catch(e) { /* silenciar error secundario */ }

return [{ json: { notified: true, error: errorMsg } }];

// =================================================================
//  PROCESAR ÓRDENES Y PREPARAR MENSAJES POR URGENCIA DE ENTREGA
// =================================================================
let data = $input.first().json;

// n8n a veces anida la respuesta
if (data.body && data.body.ordenes !== undefined) data = data.body;
if (data.data && data.data.ordenes !== undefined) data = data.data;

const ordenes = Array.isArray(data.ordenes) ? data.ordenes : [];

if (ordenes.length === 0) {
  return [{ json: { debug_input: data, hayAlertas: 'false', mensajes: [], total: 0 } }];
}

const sep = '─'.repeat(30);
const mensajes = [];

const vencHoy  = ordenes.filter(x => x.dias_restantes <= 0);
const criticas = ordenes.filter(x => x.dias_restantes > 0 && x.dias_restantes <= 3);
const aviso    = ordenes.filter(x => x.dias_restantes > 3);

// ── Encabezado resumen ───────────────────────────────────────────
let header = [
  '🚚 *ALERTAS DE FECHA LÍMITE DE ENTREGA*',
  '🗓️ ' + (data.generado || new Date().toLocaleString('es-PE')) + '  |  deudas.sekaitech.com.pe',
  sep,
  '📊 *Resumen:*',
  '   • Total con fecha próxima: *' + ordenes.length + '*'
];
if (vencHoy.length)  header.push('   • 🔴 Entrega hoy o vencida: *' + vencHoy.length + '*');
if (criticas.length) header.push('   • 🟠 Críticas (≤3d): *' + criticas.length + '*');
if (aviso.length)    header.push('   • 🟡 Aviso (>3d): *' + aviso.length + '*');
mensajes.push(header.join('\n'));

// ── Builder de ítem ─────────────────────────────────────────────
const buildItem = (item, i) => {
  const diasStr = item.dias_restantes < 0
    ? `Hace ${Math.abs(item.dias_restantes)} día(s) — VENCIDA`
    : item.dias_restantes === 0 ? '¡ENTREGA HOY!'
    : `Faltan ${item.dias_restantes} días`;

  return [
    '',
    ` *${i + 1}. OC #${item.orden_compra}*`,
    `   🏢 Entidad: ${item.entidad}`,
    `   🔧 Producto/Servicio: ${item.producto_servicio}`,
    item.empresa_factura ? `   🏬 Empresa factura: ${item.empresa_factura}` : null,
    `   💰 Monto: *${item.monto}*`,
    `   📊 Estado: ${item.estado_seguimiento}`,
    `   👤 Responsable: ${item.responsable || 'No asignado'}`,
    `   📦 Entregar: *${item.fecha_limite_entrega}* (${diasStr})`,
  ].filter(Boolean).join('\n');
};

if (vencHoy.length > 0) {
  let bloque = ['🔴 *ENTREGA VENCIDA O HOY (Acción Inmediata)*', sep];
  vencHoy.forEach((x, i) => bloque.push(buildItem(x, i)));
  mensajes.push(bloque.join('\n'));
}

if (criticas.length > 0) {
  let bloque = ['🟠 *ENTREGA CRÍTICA (1-3 días)*', sep];
  criticas.forEach((x, i) => bloque.push(buildItem(x, i)));
  mensajes.push(bloque.join('\n'));
}

if (aviso.length > 0) {
  let bloque = ['🟡 *AVISO DE ENTREGA (> 3 días)*', sep];
  aviso.forEach((x, i) => bloque.push(buildItem(x, i)));
  mensajes.push(bloque.join('\n'));
}

return [{ json: { hayAlertas: 'true', mensajes, total: ordenes.length } }];

// ============================================================
//  ENVIAR MENSAJES VÍA EVOLUTION API → GRUPO WHATSAPP ENTREGAS
// ============================================================
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '6mF28RqtJdPIZorVIbAaRBiKZoZr3a5t4d9jikNna7c=';
const EVOLUTION_INSTANCE = 'sekaitech';
const GROUP_JID          = '120363424829792074@g.us';

let results = [];

for (const item of $input.all()) {
  const mensaje = item.json.mensaje || '';
  if (!mensaje) continue;

  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
      headers: {
        'apikey': EVOLUTION_API_KEY,
        'Content-Type': 'application/json'
      },
      body: { number: GROUP_JID, text: mensaje },
      json: true,
      timeout: 15000
    });
    results.push({ json: { success: true, key: r.key } });
    await new Promise(resolve => setTimeout(resolve, 1500));
  } catch(e) {
    results.push({ json: { success: false, error: e.message } });
  }
}

return results;
